define(["core/ajax"],function(Ajax){var processResults=function(selector,results){var processed=[];if(!results||!results.users){return processed}results.users.forEach(function(user){processed.push({value:user.id,label:user.fullname+" ("+user.email+")"})});return processed};var transport=function(selector,query,success,failure){var element=document.querySelector(selector);if(!element){success([]);return}var form=element.closest("form");var tenantId=0;var clientId=0;if(form){var tenantInput=form.querySelector('input[name="tenantid"]');var clientInput=form.querySelector('input[name="clientid"]');if(tenantInput){tenantId=parseInt(tenantInput.value,10)||0}if(clientInput){clientId=parseInt(clientInput.value,10)||0}}if(!tenantId){success([]);return}if(!query||query.length<2){success([]);return}var request={methodname:"local_dsl_isp_search_users",args:{tenantid:tenantId,clientid:clientId,search:query,limit:20}};Ajax.call([request])[0].then(function(results){success(processResults(selector,results))}).catch(function(error){failure(error)})};return{processResults:processResults,transport:transport}});
